(function(){window.SmokeTest=window.SmokeTest||{},window.SmokeTest.Helpers=window.SmokeTest.Helpers||{};const l={sleep(e){try{return new Promise(t=>setTimeout(t,Math.max(0,e|0)))}catch{return Promise.resolve()}},async waitUntilTrue(e,t=400,r=40){const n=Date.now()+Math.max(0,t|0);for(;Date.now()<n;){try{if(e())return!0}catch{}await l.sleep(r)}try{return!!e()}catch{return!1}},hasEl(e){try{return!!document.getElementById(e)}catch{return!1}},safeClick(e){try{const t=document.getElementById(e);if(!t)return!1;try{return t.click(),!0}catch{return!1}}catch{return!1}},safeSetInput(e,t){try{const r=document.getElementById(e);if(!r)return!1;r.value=String(t);try{r.dispatchEvent(new Event("input",{bubbles:!0}))}catch{}try{r.dispatchEvent(new Event("change",{bubbles:!0}))}catch{}return!0}catch{return!1}},clickConfirmOk(){try{const e=document.getElementById("confirm-panel");if(!e)return!1;const t=e.querySelectorAll("button");if(!t||!t.length)return!1;for(let r=0;r<t.length;r++){const n=t[r];if(String(n&&n.textContent||"").trim().toLowerCase()==="ok")return n.click(),!0}try{return t[t.length-1].click(),!0}catch{return!1}}catch{return!1}},clickConfirmCancel(){try{const e=document.getElementById("confirm-panel");if(!e)return!1;const t=e.querySelectorAll("button");if(!t||!t.length)return!1;for(let r=0;r<t.length;r++){const n=t[r];if(String(n&&n.textContent||"").trim().toLowerCase()==="cancel")return n.click(),!0}try{return t[0].click(),!0}catch{return!1}}catch{return!1}},key(e){try{const t=new KeyboardEvent("keydown",{key:e,code:e,bubbles:!0});try{window.dispatchEvent(t)}catch{}try{document.dispatchEvent(t)}catch{}return!0}catch{return!1}}};window.SmokeTest.Helpers.Dom=l})();
